using System.Collections;
using UnityEngine;

/// <summary>Operação numérica usada por Action_SetIntVariable / Action_SetFloatVariable.</summary>
public enum VariableNumberOp
{
    Set,
    Add,
    Subtract
}

/// <summary>
/// Define o valor de uma variável bool (Etapa 8 — ver GameVariable/GameVariables).
/// Se a variável ainda não existir (em Global ou nas Variáveis Locais do NPC),
/// é criada automaticamente com este nome.
/// </summary>
[System.Serializable]
public class Action_SetBoolVariable : NpcAction
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir ainda, é criada automaticamente com este nome.")]
    public string variableName;

    public bool value = true;

    public override IEnumerator Execute(NpcController npc)
    {
        GameVariableUtil.SetBool(npc, scope, variableName, value);
        yield break;
    }
}

/// <summary>Inverte o valor actual de uma variável bool (true→false, false→true).</summary>
[System.Serializable]
public class Action_ToggleBoolVariable : NpcAction
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir ainda, é criada automaticamente (a começar em false, ficando true após o toggle).")]
    public string variableName;

    public override IEnumerator Execute(NpcController npc)
    {
        bool current = GameVariableUtil.GetBool(npc, scope, variableName);
        GameVariableUtil.SetBool(npc, scope, variableName, !current);
        yield break;
    }
}

/// <summary>Define, soma ou subtrai um valor a uma variável int.</summary>
[System.Serializable]
public class Action_SetIntVariable : NpcAction
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir ainda, é criada automaticamente com este nome.")]
    public string variableName;

    [Tooltip("Set = define o valor directamente. Add/Subtract = soma/subtrai ao valor actual da variável.")]
    public VariableNumberOp operation = VariableNumberOp.Set;

    public int value;

    public override IEnumerator Execute(NpcController npc)
    {
        int result = value;

        if (operation != VariableNumberOp.Set)
        {
            int current = GameVariableUtil.GetInt(npc, scope, variableName);
            result = operation == VariableNumberOp.Add ? current + value : current - value;
        }

        GameVariableUtil.SetInt(npc, scope, variableName, result);
        yield break;
    }
}

